int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        // one plate
        printf("1\n");
        printf("%d\n", N);
        for (int i = 1; i <= N; ++i) {
            printf("1\n");
            printf("%d 1\n", i);
        }
    }
    return 0;
}

