import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        StringBuilder out = new StringBuilder();
        int T = fs.nextInt();
        while (T-- > 0) {
            int N = fs.nextInt();
            out.append(1).append('\n');          // M
            out.append(N).append('\n');          // capacity
            for (int i = 1; i <= N; i++) {
                out.append(1).append('\n');      // Ki
                out.append(i).append(' ').append(1).append('\n'); // fruit i to plate 1
            }
        }
        System.out.print(out.toString());
    }

    // Simple fast scanner
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return val * sign;
        }
    }
}

code.Python3:
#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        out_lines.append('1')          # M
        out_lines.append(str(N))       # capacity
        for i in range(1, N + 1):
            out_lines.append('1')      # Ki
            out_lines.append(f"{i} 1")
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

